import math

def parse_versioninfo(v):
    if not isinstance(v, str) or not v.strip():
        return (None, None)
    try:
        j = json.loads(v)
        isrel = j.get('IsRelease')
        ordn = j.get('Ordinal')
        return (isrel, ordn)
    except Exception:
        # attempt crude parse
        isrel = None
        ordn = None
        if 'IsRelease' in v:
            m = re.search(r'"IsRelease"\s*:\s*(true|false)', v, re.IGNORECASE)
            if m:
                isrel = True if m.group(1).lower()=='true' else False
        m2 = re.search(r'"Ordinal"\s*:\s*(\d+)', v)
        if m2:
            ordn = int(m2.group(1))
        return (isrel, ordn)

# Apply only to NPM
